const Assets = {
  data: SVG_ASSET_DATA,

  // Inject an asset SVG into targetElement.
  // options: { className, interactive }
  inject(assetId, targetElement, options = {}) {
    const asset = this.data[assetId];
    if (!asset) {
      console.error(`SVG Asset not found: ${assetId}`);
      return;
    }
    const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
    svg.setAttribute('viewBox', asset.viewBox);
    svg.setAttribute('width', '100%');
    svg.setAttribute('height', '100%');
    svg.setAttribute('aria-hidden', 'true');
    if (options.className) svg.classList.add(options.className);
    svg.innerHTML = asset.content;
    targetElement.innerHTML = '';
    targetElement.appendChild(svg);
    if (options.interactive && window.registerGradientInteraction) {
      window.registerGradientInteraction(svg);
    }
  },

  // Return a complete <svg ...> string for use with PretextEngine's svgs dict.
  svgString(assetId) {
    const a = this.data[assetId];
    if (!a) return '';
    return `<svg viewBox="${a.viewBox}" width="100%" height="100%" aria-hidden="true">${a.content}</svg>`;
  }
};

window.Assets = Assets;
